#!/usr/bin/env python3
"""M141-6 cross-language parity gate (#1807).

Asserts that @orchestkit/hook-contract (npm) and orchestkit-hook-contract
(PyPI) emit semantically identical hook contracts:

  - Same set of 19 event names
  - For each event: same payload.required field names (set equality)
  - For each event: same payload.properties field names (set equality)
  - For each field: same JSON Schema type category

The two codegen pipelines (packages/hook-contract/scripts/codegen.mjs and
packages/hook-contract-py/scripts/codegen-py.py) both read the same
spec/hook-events.spec.yml. The per-side --check drift gates already
ensure each side matches the spec. THIS gate adds the stronger property:
that the two emits are also semantically equivalent to each other.

Why both checks are needed: a subtle bug in either codegen could let
both --check gates pass while the npm and PyPI outputs diverge (e.g.
one emits `tool_input` as type:string and the other as type:object).
This script catches that case mechanically.

Usage:
  python scripts/parity-check.py

Requires:
  - Built npm package: cd packages/hook-contract && npm run build
  - Installed PyPI package: cd packages/hook-contract-py && pip install -e .

CI runs both build steps before invoking this script — see
.github/workflows/contract-parity.yml.
"""

from __future__ import annotations

import json
import subprocess
import sys
from pathlib import Path
from typing import Any

REPO_ROOT = Path(__file__).resolve().parent.parent
NPM_PKG_DIR = REPO_ROOT / "packages" / "hook-contract"


def extract_npm_schemas() -> dict[str, dict[str, Any]]:
    """Extract HOOK_EVENT_SCHEMAS from the built npm package via node."""
    esm_entry = NPM_PKG_DIR / "dist" / "esm" / "index.js"
    if not esm_entry.exists():
        print(
            f"[parity-check] npm package not built. Expected {esm_entry}. "
            f"Run `cd packages/hook-contract && npm run build` first.",
            file=sys.stderr,
        )
        sys.exit(1)

    script = (
        "import {HOOK_EVENT_SCHEMAS, HOOK_EVENT_NAMES} from './dist/esm/index.js';"
        " console.log(JSON.stringify({"
        " HOOK_EVENT_NAMES: HOOK_EVENT_NAMES,"
        " HOOK_EVENT_SCHEMAS: HOOK_EVENT_SCHEMAS"
        " }));"
    )
    result = subprocess.run(
        ["node", "--input-type=module", "-e", script],
        cwd=NPM_PKG_DIR,
        capture_output=True,
        text=True,
        check=False,
    )
    if result.returncode != 0:
        print(
            f"[parity-check] node extraction failed:\n{result.stderr}",
            file=sys.stderr,
        )
        sys.exit(1)
    data = json.loads(result.stdout)
    return data  # type: ignore[no-any-return]


def extract_pypi_schemas() -> dict[str, Any]:
    """Import HOOK_EVENT_SCHEMAS from the installed PyPI package."""
    try:
        from orchestkit_hook_contract import (  # type: ignore[import-not-found]
            HOOK_EVENT_NAMES,
            HOOK_EVENT_SCHEMAS,
        )
    except ImportError as e:
        print(
            f"[parity-check] PyPI package not importable: {e}. "
            f"Run `cd packages/hook-contract-py && pip install -e .` first.",
            file=sys.stderr,
        )
        sys.exit(1)
    return {
        "HOOK_EVENT_NAMES": list(HOOK_EVENT_NAMES),
        "HOOK_EVENT_SCHEMAS": HOOK_EVENT_SCHEMAS,
    }


def field_type_category(schema_fragment: dict[str, Any]) -> str:
    """Reduce a JSON Schema fragment to its type category for comparison.

    Both codegens emit the same JSON Schema vocabulary, but small
    cosmetic differences (e.g. presence/absence of description) shouldn't
    fail the gate. We compare by `type` only; descriptions diverge often
    because TS emits doc comments differently than Python docstrings.
    """
    t = schema_fragment.get("type")
    if t == "array":
        items_type = schema_fragment.get("items", {}).get("type", "unknown")
        return f"array<{items_type}>"
    if t is None:
        return "any"
    return str(t)


def compare_payload(
    _event: str,
    npm_payload: dict[str, Any],
    py_payload: dict[str, Any],
) -> list[str]:
    """Return a list of human-readable divergences for one event.

    `_event` is unused inside the function — the caller uses it for the
    section header. Kept in the signature for call-site readability.
    """
    errors: list[str] = []

    npm_required = set(npm_payload.get("required") or [])
    py_required = set(py_payload.get("required") or [])
    if npm_required != py_required:
        only_npm = sorted(npm_required - py_required)
        only_py = sorted(py_required - npm_required)
        if only_npm:
            errors.append(f"  required only in npm: {only_npm}")
        if only_py:
            errors.append(f"  required only in PyPI: {only_py}")

    npm_props = npm_payload.get("properties") or {}
    py_props = py_payload.get("properties") or {}
    npm_keys = set(npm_props.keys())
    py_keys = set(py_props.keys())
    if npm_keys != py_keys:
        only_npm = sorted(npm_keys - py_keys)
        only_py = sorted(py_keys - npm_keys)
        if only_npm:
            errors.append(f"  property only in npm: {only_npm}")
        if only_py:
            errors.append(f"  property only in PyPI: {only_py}")

    for field in sorted(npm_keys & py_keys):
        npm_type = field_type_category(npm_props[field])
        py_type = field_type_category(py_props[field])
        if npm_type != py_type:
            errors.append(f"  field '{field}' type mismatch: npm={npm_type} vs PyPI={py_type}")

    return errors


def main() -> int:
    npm = extract_npm_schemas()
    py = extract_pypi_schemas()

    errors: list[str] = []

    # 1. Same set of event names
    npm_names = set(npm["HOOK_EVENT_NAMES"])
    py_names = set(py["HOOK_EVENT_NAMES"])
    if npm_names != py_names:
        only_npm = sorted(npm_names - py_names)
        only_py = sorted(py_names - npm_names)
        if only_npm:
            errors.append(f"event names only in npm: {only_npm}")
        if only_py:
            errors.append(f"event names only in PyPI: {only_py}")

    # 2. Per-event payload schema parity
    for event in sorted(npm_names & py_names):
        npm_payload = npm["HOOK_EVENT_SCHEMAS"][event].get("properties", {}).get("payload", {})
        py_payload = py["HOOK_EVENT_SCHEMAS"][event].get("properties", {}).get("payload", {})
        per_event = compare_payload(event, npm_payload, py_payload)
        if per_event:
            errors.append(f"\n{event}:")
            errors.extend(per_event)

    if errors:
        print(
            "[parity-check] FAILED: npm and PyPI hook-contract emit diverge.\n",
            file=sys.stderr,
        )
        for line in errors:
            print(line, file=sys.stderr)
        print(
            "\nFix: identify which codegen drifted from the other, regenerate, "
            "and commit. Both should emit identical schemas from "
            "spec/hook-events.spec.yml.",
            file=sys.stderr,
        )
        return 1

    total_events = len(npm_names)
    total_with_payload = sum(
        1
        for e in npm_names
        if (npm["HOOK_EVENT_SCHEMAS"][e].get("properties", {}).get("payload", {}).get("properties"))
    )
    print(
        f"[parity-check] OK: npm + PyPI emit identical contract "
        f"({total_events} events, {total_with_payload} with typed payloads)."
    )
    return 0


if __name__ == "__main__":
    sys.exit(main())
